import { type DaemonPaths } from "./protocol.js";
/**
 * Wait for the daemon the lock holder is bringing up. We reach here only after
 * losing the spawn lock, so another ensureDaemon is (re)spawning; prefer to
 * return once the answering daemon reports OUR local build, so a build-mismatch
 * respawn can't hand us the stale daemon that is about to be reaped (the window
 * Bugbot flagged). If the local build is unknowable, the daemon doesn't report
 * one, or a matching build never appears within the timeout (a rare cross-install
 * race where the holder is spawning a different build), fall back to the prior
 * waitForSocket contract: return only if a daemon is responding RIGHT NOW. We
 * re-ping at the deadline rather than trusting an earlier success, because the
 * holder may have reaped the old daemon and not yet bound the replacement, and
 * returning on a dead socket would falsely claim readiness.
 */
export declare function waitForLockHolderDaemon(socketPath: string, timeoutMs: number, localBuild?: string): Promise<void>;
/**
 * Whether a running daemon's reported build is safe to reuse. A daemon that
 * reports OUR build matches. A daemon that reports a DIFFERENT build, or reports
 * NONE at all (too old to answer `build` on ping - the exact stale daemon that
 * kept serving old code), does NOT match and must be reaped + respawned. When we
 * can't fingerprint our own build (`unknown`), we can't judge, so we accept
 * whatever is running rather than respawn-loop.
 */
export declare function buildMatches(localBuild: string, remoteBuild: string | null): boolean;
/**
 * Reap ALL daemons bound to this socket, not just the pidfile's. Called once,
 * under the spawn lock, immediately before spawning a fresh daemon, so every
 * respawn path (no pidfile, stale pidfile, build mismatch, unresponsive socket)
 * converges on a single live daemon instead of orphaning the previous one.
 */
export declare function reapAllDaemons(paths: DaemonPaths): Promise<void>;
export declare function ensureDaemon(paths?: DaemonPaths): Promise<void>;
